字典与集合字典 (dict)字典是键值对的集合，key 必须是不可变类型，3.7+ 保证插入顺序。
创建d1 = &#123;&quot;name&quot;: &quot;GodY&quot;, &quot;age&quot;: 22&#125;d2 = dict(name=&quot;GodY&quot;, age=22)d3 = dict([(&quot;name&quot;, &quot;GodY&quot;), (&quot;age&quot;, 22)])d4 = &#123;x: x**2 for x in range(5)&#125;  # &#123;0:0, 1:1, 2:4, 3:9, 4:16&#125;d5 = dict.fromkeys([&quot;a&quot;, &quot;b&quot;, &quot;c&quot;], 0)  # &#123;&#x27;a&#x27;:0, &#x27;b&#x27;:0, &#x27;c&#x27;:0&#125;

基本操作d = &#123;&quot;name&quot;: &quot;GodY&quot;, &quot;age&quot;: 22&#125;# 访问print(d[&quot;name&quot;])         # GodY（key 不存在会报错）print(d.get(&quot;phone&quot;))    # None（key 不存在返回 None）print(d.get(&quot;phone&quot;, &quot;无&quot;))  # 无（指定默认值）# 增/改d[&quot;city&quot;] = &quot;苏州&quot;       # 新增d[&quot;age&quot;] = 23            # 修改# 删除del d[&quot;age&quot;]             # 删除 keypopped = d.pop(&quot;name&quot;)   # 弹出并返回值item = d.popitem()       # 弹出最后一个键值对（3.7+）d.clear()                # 清空# 合并（3.9+）a = &#123;&quot;x&quot;: 1, &quot;y&quot;: 2&#125;b = &#123;&quot;y&quot;: 3, &quot;z&quot;: 4&#125;merged = a | b           # &#123;&#x27;x&#x27;:1, &#x27;y&#x27;:3, &#x27;z&#x27;:4&#125;（后者覆盖前者）a |= b                   # a 原地更新为 &#123;&#x27;x&#x27;:1, &#x27;y&#x27;:3, &#x27;z&#x27;:4&#125;# 3.8 及以前merged = &#123;**a, **b&#125;

遍历d = &#123;&quot;a&quot;: 1, &quot;b&quot;: 2, &quot;c&quot;: 3&#125;# 遍历 keyfor k in d:    print(k)for k in d.keys():    print(k)# 遍历 valuefor v in d.values():    print(v)# 遍历 key-valuefor k, v in d.items():    print(f&quot;&#123;k&#125; → &#123;v&#125;&quot;)

常用模式# 计数器from collections import Countertext = &quot;hello world&quot;counts = Counter(text)print(counts)  # Counter(&#123;&#x27;l&#x27;: 3, &#x27;o&#x27;: 2, ...&#125;)print(counts.most_common(2))  # [(&#x27;l&#x27;, 3), (&#x27;o&#x27;, 2)]# 默认值字典from collections import defaultdictdd = defaultdict(list)dd[&quot;a&quot;].append(1)  # 即使 &quot;a&quot; 不存在也不会报错print(dd)          # &#123;&#x27;a&#x27;: [1]&#125;# 有序字典（3.7+ 普通 dict 也有序了，但 OrderedDict 还有额外功能）from collections import OrderedDictod = OrderedDict()od[&quot;first&quot;] = 1od[&quot;second&quot;] = 2od.move_to_end(&quot;first&quot;)  # 把 &quot;first&quot; 移到最后

集合 (set)集合是无序、不重复元素的集合，基于哈希表实现。
创建s1 = &#123;1, 2, 3, 4, 5&#125;s2 = set([1, 2, 2, 3, 3, 3])  # &#123;1, 2, 3&#125;（自动去重）s3 = set()                      # 空集合（&#123;&#125; 是空字典！）s4 = &#123;x for x in range(10) if x % 2 == 0&#125;  # &#123;0, 2, 4, 6, 8&#125;

集合运算a = &#123;1, 2, 3, 4&#125;b = &#123;3, 4, 5, 6&#125;# 基本运算print(a | b)    # 并集 &#123;1, 2, 3, 4, 5, 6&#125;print(a &amp; b)    # 交集 &#123;3, 4&#125;print(a - b)    # 差集 &#123;1, 2&#125;（a 有 b 没有）print(a ^ b)    # 对称差 &#123;1, 2, 5, 6&#125;（不同时属于两个集合的）# 就地修改a |= b   # a = a | ba &amp;= b   # a = a &amp; ba -= b   # a = a - b# 关系判断print(&#123;1, 2&#125; &lt;= &#123;1, 2, 3&#125;)  # True（子集）print(&#123;1, 2, 3&#125; &gt;= &#123;1, 2&#125;)  # True（超集）print(&#123;1, 2&#125;.isdisjoint(&#123;3, 4&#125;))  # True（不相交）

增删查s = &#123;1, 2, 3&#125;s.add(4)          # &#123;1, 2, 3, 4&#125;s.add(2)          # 没变化（已存在）s.remove(3)       # &#123;1, 2, 4&#125;（元素不存在会报错）s.discard(10)     # 不报错（不存在就什么都不做）popped = s.pop()  # 随机弹出一个s.clear()         # 清空

实际用途# 去重unique = list(set([1, 2, 2, 3, 3, 3]))# 成员检查（O(1)，比列表的 O(n) 快）valid_ids = &#123;1, 5, 10, 20&#125;if user_id in valid_ids:    grant_access()# 找共同元素friends_a = &#123;&quot;Alice&quot;, &quot;Bob&quot;, &quot;Charlie&quot;&#125;friends_b = &#123;&quot;Bob&quot;, &quot;David&quot;, &quot;Eve&quot;&#125;mutual = friends_a &amp; friends_b  # &#123;&quot;Bob&quot;&#125;

frozenset（不可变集合）fs = frozenset([1, 2, 3])# fs.add(4)        # AttributeError# fs.remove(1)     # AttributeError# 可以作为字典 keygraph = &#123;frozenset([&quot;A&quot;, &quot;B&quot;]): 10&#125;  # 边的权重
